section.sourcecode:
{
  "jsonrpc": "2.0",
  "id": 1,
  "result": {
    "tools": [
      {
        "name": "web_search",
        "title": "Web Search",
        "description": "Search the web for current information",
        "inputSchema": {
          "type": "object",
          "properties": {
            "query": { "type": "string", "description": "Search query" }
          },
          "required": ["query"]
        }
      },
      {
        "name": "image_generate",
        "title": "Image Generation",
        "description": "Generate images from text prompts",
        "inputSchema": {
          "type": "object",
          "properties": {
            "prompt": { "type": "string" },
            "size": { "type": "string", "enum": ["256x256", "512x512", "1024x1024"] }
          },
          "required": ["prompt"]
        }
      }
    ]
  }
}

{
  "jsonrpc": "2.0",
  "id": 5,
  "result": {
    "content": [
      {
        "type": "text",
        "text": "Here are the latest AI news headlines:\n\n1. OpenAI announces GPT-5...\n2. Google releases Gemini 2.0..."
      }
    ]
  },
  "receipt": "eyJ0eCI6IjB4YWJjZCJ9"
}

{
  "jsonrpc": "2.0",
  "id": 6,
  "result": {
    "content": [
      {
        "type": "text",
        "text": "Analysis complete. See attached report."
      },
      {
        "type": "resource",
        "resource": {
          "uri": "report://analysis/2025-01-19",
          "mimeType": "application/pdf",
          "title": "Full Analysis Report"
        }
      }
    ]
  },
  "receipt": "eyJ0eCI6IjB4ZWZnaCJ9"
}

{
  "jsonrpc": "2.0",
  "id": 8,
  "result": {
    "content": [
      {
        "type": "text",
        "text": "Error: Rate limit exceeded. Please try again in 60 seconds."
      }
    ],
    "isError": true
  }
}
